const invoiceDays = Number($env.INVOICE_PARSED_DATA_RETENTION_DAYS || 180);
const opsEventDays = Number($env.OPS_EVENTS_RETENTION_DAYS || 90);
const minInvoiceDays = 30;
const minOpsDays = 30;
if (!Number.isFinite(invoiceDays) || invoiceDays < minInvoiceDays) throw new Error(`INVOICE_PARSED_DATA_RETENTION_DAYS must be >= ${minInvoiceDays}`);
if (!Number.isFinite(opsEventDays) || opsEventDays < minOpsDays) throw new Error(`OPS_EVENTS_RETENTION_DAYS must be >= ${minOpsDays}`);
return [{ json: { invoiceDays, opsEventDays } }];

parameters.query:
DELETE FROM ops_events
WHERE ts < NOW() - ('{{$json.opsEventDays}} days')::interval
RETURNING id;

